import{_ as e,o,c as t,a}from"./app.fddaad14.js";const k=JSON.parse('{"title":"GDAN v. Miller, May 2021","description":"","frontmatter":{},"headers":[{"level":2,"title":"Case","slug":"case","link":"#case","children":[]},{"level":2,"title":"Proceedings","slug":"proceedings","link":"#proceedings","children":[]}],"relativePath":"government/court-cases-precedents/gdan_v_miller_may_2021.md","lastUpdated":1666920751000}'),n={name:"government/court-cases-precedents/gdan_v_miller_may_2021.md"},l=a('<h1 id="gdan-v-miller-may-2021" tabindex="-1">GDAN v. Miller, May 2021 <a class="header-anchor" href="#gdan-v-miller-may-2021" aria-hidden="true">#</a></h1><h2 id="case" tabindex="-1">Case <a class="header-anchor" href="#case" aria-hidden="true">#</a></h2><p>With Aki presiding, on 10th May 2021, GDAN charged Miller with Raiding.</p><h2 id="proceedings" tabindex="-1">Proceedings <a class="header-anchor" href="#proceedings" aria-hidden="true">#</a></h2><p><strong>GDAN:</strong></p><blockquote><p>I would like to sue Miller for raiding me</p></blockquote><p><strong>SpaceVolcano:</strong></p><blockquote><p>The courts will hear GDAN vs Miller on the charge of Raiding</p></blockquote><blockquote><p>Aki will be presiding</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>Thank you High Justice. The court will now come to order.</p></blockquote><blockquote><p>GDAN, As the prosecution, I call on you to make an opening statement</p></blockquote><p><strong>GDAN:</strong></p><blockquote><p>I returned from a long hiatus to find some of my chests broken into located at my homestead SW of NYC. I checked my snitch logs and it showed the only person to have broken any chest was Millers.</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>Miller, How do you plead to the charge of Raiding</p></blockquote><p><strong>Miller:</strong></p><blockquote><p>I plead Not Guilty</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>The court recognizes the not guilty plea. Miller the court calls on you to present an opening statement</p></blockquote><p><strong>Miller:</strong></p><blockquote><p>I know what it looks like but it wasn&#39;t me</p></blockquote><blockquote><p>It was my evil clone.</p></blockquote><blockquote><p>you honor I would like to change my plea, I know what I have done is wrong and would like this dealt with smoothly. I plea guilty</p></blockquote><blockquote><p>I would also like to point out to the court that the scene of the crime was not marked with any indicators such as sign sating who&#39;s it was nor was it claimed. To a player that was about two days old to the sever im sure you can see how this can be confusing.</p></blockquote><blockquote><p>The second thing i would like to note is that there was already chests half broken and blocks that helped me get into the area. As a new player i though this meant it was fair game seeing as someone else already tried to raid it.</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>I see, the court has observed the plea change.</p></blockquote><blockquote><p>GDAN, How much was stolen from the chests?</p></blockquote><p><strong>NeoTide:</strong></p><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/842490178978185226/2021-05-13_15.54.33.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/842490178978185226/2021-05-13_15.54.33.png</a></p></blockquote><p><strong>GDAN:</strong></p><blockquote><p>Aki, I believe some compacted obsidian, some enchanted/unenchanted tools and some E blocks were stolen but am unsure since it happened during a period of time during which I was not active.</p></blockquote><blockquote><p>I would also like to rebute Miller&#39;s claim that the area was unclaimed, it was not. It is clearly indicated as claimed by Yoahtl on the map</p></blockquote><p><strong>Miller:</strong></p><blockquote><p>I cant confirm i have the tools but am unaware of the compacted obsidian and E blocks nor do i know what they are</p></blockquote><p><strong>Aki:</strong></p><blockquote><p>GDAN, following discussion with Miller, he states that he found the area in significant disrepair, with looting having already taken place. For this reason, and the reason I saw when he accidentally died in the trench, I do believe the tools were looted, but the obsidian and the emeralds were not raided in the same way.</p></blockquote><blockquote><p>Ok, essentially, Miller declared guilty to the charge. I will say that he has said multiple times that he didn&#39;t see any Eblocks or obby, and given that he was inquiring about their value to me later in the conversation a few days ago casts doubt he would have taken them. So, Miller is declared guilty of theft of Gdans tools and griefing. Miller is to be pearled for one week and all tools returned.</p></blockquote><blockquote><p>GDAN, Given the current situation, later this week one of the yoahtlan government people will collect your tools and bring it to you.</p></blockquote>',40),i=[l];function s(r,c,h,d,p,u){return o(),t("div",null,i)}const b=e(n,[["render",s]]);export{k as __pageData,b as default};
